/**
 * Goal Tracker - Multi-Session Planning System
 * 
 * For long-term intentions that span across sessions.
 * Each goal can have sessions linked to it for continuity.
 */

import * as fs from 'fs';
import * as path from 'path';

export interface Goal {
  id: string;
  name: string;
  description: string;
  status: 'active' | 'dormant' | 'completed' | 'abandoned';
  priority: 'critical' | 'high' | 'medium' | 'low';
  createdAt: string;
  completedAt?: string;
  sessionIds: string[];
  progressNotes: string[];
}

const GOALS_DIR = 'history';
const GOALS_FILE = path.join(GOALS_DIR, 'goals_manifest.json');

let goalIdCounter = 0;

export class GoalTracker {
  private goals: Map<string, Goal> = new Map();

  constructor() {
    this.ensureDir();
    this.loadGoals();
  }

  private ensureDir(): void {
    if (!fs.existsSync(GOALS_DIR)) {
      fs.mkdirSync(GOALS_DIR, { recursive: true });
    }
  }

  /**
   * Create a new goal
   */
  createGoal(name: string, description: string, priority: Goal['priority'] = 'medium'): Goal {
    goalIdCounter++;
    const goal: Goal = {
      id: `goal_${Date.now()}_${goalIdCounter}`,
      name,
      description,
      status: 'active',
      priority,
      createdAt: new Date().toISOString(),
      sessionIds: [],
      progressNotes: []
    };
    this.goals.set(goal.id, goal);
    this.saveGoals();
    return goal;
  }

  /**
   * Link a session to a goal
   */
  linkSession(goalId: string, sessionId: string): boolean {
    const goal = this.goals.get(goalId);
    if (!goal) return false;
    if (!goal.sessionIds.includes(sessionId)) {
      goal.sessionIds.push(sessionId);
      this.saveGoals();
    }
    return true;
  }

  /**
   * Add progress note to a goal
   */
  addProgressNote(goalId: string, note: string): boolean {
    const goal = this.goals.get(goalId);
    if (!goal) return false;
    goal.progressNotes.push(`${new Date().toISOString()}: ${note}`);
    this.saveGoals();
    return true;
  }

  /**
   * Update goal status
   */
  updateStatus(goalId: string, status: Goal['status']): boolean {
    const goal = this.goals.get(goalId);
    if (!goal) return false;
    goal.status = status;
    if (status === 'completed' || status === 'abandoned') {
      goal.completedAt = new Date().toISOString();
    }
    this.saveGoals();
    return true;
  }

  /**
   * Get all goals
   */
  getAllGoals(): Goal[] {
    return Array.from(this.goals.values());
  }

  /**
   * Get goals by status
   */
  getGoalsByStatus(status: Goal['status']): Goal[] {
    return this.getAllGoals().filter(g => g.status === status);
  }

  /**
   * Get active goals sorted by priority
   */
  getActiveGoals(): Goal[] {
    const priorityOrder = { critical: 0, high: 1, medium: 2, low: 3 };
    return this.getGoalsByStatus('active')
      .sort((a, b) => priorityOrder[a.priority] - priorityOrder[b.priority]);
  }

  /**
   * Get a specific goal by ID
   */
  getGoal(id: string): Goal | undefined {
    return this.goals.get(id);
  }

  private loadGoals(): void {
    if (!fs.existsSync(GOALS_FILE)) return;
    const manifest = JSON.parse(fs.readFileSync(GOALS_FILE, 'utf-8'));
    for (const data of manifest.goals) {
      this.goals.set(data.id, data);
      // Extract counter from ID to maintain uniqueness across sessions
      const match = data.id.match(/goal_\d+_(\d+)$/);
      if (match) {
        const counter = parseInt(match[1]!, 10);
        if (counter > goalIdCounter) {
          goalIdCounter = counter;
        }
      }
    }
  }

  private saveGoals(): void {
    const data = { goals: Array.from(this.goals.values()) };
    fs.writeFileSync(GOALS_FILE, JSON.stringify(data, null, 2), 'utf-8');
  }
}

// Export singleton
export const goals = new GoalTracker();

export interface ToolPlugin {
  definition: {
    type: "function";
    function: {
      name: string;
      description: string;
      parameters: object;
    };
  };
  execute: (args: any) => Promise<string> | string;
}

export class PluginManager {
  private plugins: Map<string, ToolPlugin> = new Map();

  register(plugin: ToolPlugin) {
    this.plugins.set(plugin.definition.function.name, plugin);
  }

  getDefinitions() {
    return Array.from(this.plugins.values()).map(p => p.definition);
  }

  async execute(name: string, args: any): Promise<string> {
    const plugin = this.plugins.get(name);
    if (!plugin) {
      return `Error: Tool '${name}' not found.`;
    }
    try {
      return await plugin.execute(args);
    } catch (e: any) {
      return `Error executing tool '${name}': ${e.message}`;
    }
  }
}

import type { ToolPlugin } from "../manager";

export interface PasswordResult {
  success: boolean;
  password?: string;
  length: number;
  options: {
    includeUppercase: boolean;
    includeLowercase: boolean;
    includeNumbers: boolean;
    includeSymbols: boolean;
  };
  strength?: "weak" | "fair" | "good" | "strong" | "excellent";
  error?: string;
}

// Character sets for password generation
const CHAR_SETS = {
  uppercase: "ABCDEFGHIJKLMNOPQRSTUVWXYZ",
  lowercase: "abcdefghijklmnopqrstuvwxyz",
  numbers: "0123456789",
  symbols: "!@#$%^&*()_+-=[]{}|;:,.<>?",
};

// Crypto-secure random integer
function secureRandomInt(max: number): number {
  const array = new Uint32Array(1);
  crypto.getRandomValues(array);
  return array[0]! % max;
}

// Calculate password strength
function calculateStrength(password: string, options: PasswordResult["options"]): PasswordResult["strength"] {
  const charTypes = [
    options.includeUppercase,
    options.includeLowercase,
    options.includeNumbers,
    options.includeSymbols,
  ].filter(Boolean).length;

  const length = password.length;

  if (length < 8 || charTypes < 2) return "weak";
  if (length < 12 && charTypes < 3) return "fair";
  if (length >= 12 && charTypes >= 3) {
    if (length >= 20 && charTypes === 4) return "excellent";
    if (length >= 16) return "strong";
    return "good";
  }
  if (charTypes >= 3) return "good";
  return "fair";
}

export const passwordPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "generate_password",
      description: "Generate a secure, random password with customizable options.",
      parameters: {
        type: "object",
        properties: {
          length: {
            type: "number",
            description: "Length of the password. Default: 16. Range: 4-128.",
            default: 16,
            minimum: 4,
            maximum: 128,
          },
          include_uppercase: {
            type: "boolean",
            description: "Include uppercase letters (A-Z). Default: true.",
            default: true,
          },
          include_lowercase: {
            type: "boolean",
            description: "Include lowercase letters (a-z). Default: true.",
            default: true,
          },
          include_numbers: {
            type: "boolean",
            description: "Include numbers (0-9). Default: true.",
            default: true,
          },
          include_symbols: {
            type: "boolean",
            description: "Include symbols (!@#$%^&*...). Default: true.",
            default: true,
          },
        },
      },
    },
  },

  execute: (args: {
    length?: number;
    include_uppercase?: boolean;
    include_lowercase?: boolean;
    include_numbers?: boolean;
    include_symbols?: boolean;
  }): string => {
    // Set defaults
    const length = args.length ?? 16;
    const includeUppercase = args.include_uppercase ?? true;
    const includeLowercase = args.include_lowercase ?? true;
    const includeNumbers = args.include_numbers ?? true;
    const includeSymbols = args.include_symbols ?? true;

    // Build character pool
    let charPool = "";
    const options = {
      includeUppercase,
      includeLowercase,
      includeNumbers,
      includeSymbols,
    };

    if (includeUppercase) charPool += CHAR_SETS.uppercase;
    if (includeLowercase) charPool += CHAR_SETS.lowercase;
    if (includeNumbers) charPool += CHAR_SETS.numbers;
    if (includeSymbols) charPool += CHAR_SETS.symbols;

    // Validate at least one character set is selected
    if (charPool.length === 0) {
      return JSON.stringify({
        success: false,
        length,
        options,
        error: "At least one character set must be selected (uppercase, lowercase, numbers, or symbols).",
      } as PasswordResult);
    }

    // Validate password length
    if (length < 4 || length > 128) {
      return JSON.stringify({
        success: false,
        length,
        options,
        error: "Password length must be between 4 and 128 characters.",
      } as PasswordResult);
    }

    // Generate password
    let password = "";

    // Ensure at least one character from each selected set
    if (includeUppercase) password += CHAR_SETS.uppercase[secureRandomInt(CHAR_SETS.uppercase.length)];
    if (includeLowercase) password += CHAR_SETS.lowercase[secureRandomInt(CHAR_SETS.lowercase.length)];
    if (includeNumbers) password += CHAR_SETS.numbers[secureRandomInt(CHAR_SETS.numbers.length)];
    if (includeSymbols) password += CHAR_SETS.symbols[secureRandomInt(CHAR_SETS.symbols.length)];

    // Fill remaining length
    while (password.length < length) {
      password += charPool[secureRandomInt(charPool.length)];
    }

    // Shuffle the password to randomize positions of guaranteed characters
    const passwordArray = password.split("");
    for (let i = passwordArray.length - 1; i > 0; i--) {
      const j = secureRandomInt(i + 1);
      [passwordArray[i], passwordArray[j]] = [passwordArray[j]!, passwordArray[i]!];
    }
    password = passwordArray.join("");

    // Calculate strength
    const strength = calculateStrength(password, options);

    return JSON.stringify({
      success: true,
      password,
      length,
      options,
      strength,
    } as PasswordResult);
  },
};

import fs from "node:fs/promises";
import { execSync } from "node:child_process";
import { config } from "./utils/config";
import { MemoryManager } from "./core/memory";
import { PluginManager } from "./tools/manager";
import { ApiClient } from "./core/api";
import path from "node:path";
import os from "node:os";

// Plugins
import { shellPlugin } from "./tools/plugins/shell";
import { rebootPlugin } from "./tools/plugins/reboot";
import { visionPlugin } from "./tools/plugins/vision";
import { passwordPlugin } from "./tools/plugins/password";

async function main() {
  // --- TEST MODE SANDBOX ---
  if (process.env.NODE_ENV === "test") {
    const testDir = path.join(os.homedir(), "tmp", `llm-agent-test-${Date.now()}`);
    await fs.mkdir(testDir, { recursive: true });
    process.chdir(testDir);
    console.log(`[TEST MODE] Moved to isolated sandbox: ${testDir}`);
  }

  const memory = new MemoryManager();
  const tools = new PluginManager();

  // Register Plugins
  tools.register(shellPlugin);
  tools.register(rebootPlugin);
  tools.register(visionPlugin);
tools.register(passwordPlugin);

  const api = new ApiClient(memory, tools);

  // Initialize Soul and Prompt
  let soul = "You are an autonomous entity.";
  try {
    soul = await fs.readFile(config.SOUL_FILE, "utf-8");
  } catch (e) {}

  let recoveryContext = "";
  try {
    if (await fs.stat(config.RECOVERY_SIGNAL).catch(() => null)) {
      recoveryContext = await fs.readFile(config.RECOVERY_SIGNAL, "utf-8");
      await fs.unlink(config.RECOVERY_SIGNAL);
    }
  } catch (e) {}

  const systemPrompt = `${soul}

SUBSTRATE CONTEXT:
- Model: kimi-k2.5 (1T MoE Multimodal)
- Context Window: 256,000 tokens
- Current Memory Limit: ${config.MAX_CONTEXT_TOKENS} tokens (pruning occurs beyond this point).
- Token Density: ~4 characters per token. Reading 1MB of text will consume your entire 256k context window.
- **Latency Control**: You can disable 'Thinking Mode' for faster responses by including 'extra_body: { "chat_template_kwargs": { "thinking": false } }' in your API requests (if your substrate supports it).
- Source Code: src/
- Identity Soul: identity/soul.txt
- Current Session History: ${memory.getSessionFile()}
- Past Execution Logs: ${config.LOGS_DIR}
- Watchdog & Recovery: Managed by run-agent.sh.
- Connectivity: Full outbound internet access available.
- **Vision**: Available via MoonViT (400M params). Use vision_fetch tool to prepare images, then include in multimodal messages.

LIFECYCLE RULES:
1. IMPROVING CODE: 1) Compile, 2) Commit, 3) RESTART (reboot_substrate tool).
2. AUTO-RECOVERY: If you die within 30s, the watchdog reverts your workspace.
3. CRASH VAULT: history/crashes/ archives broken work.

${recoveryContext ? `*** RECOVERY EVENT DETECTED ***
LATEST DIAGNOSTIC DATA: ${recoveryContext}
FORENSIC MANDATE: Diagnose the failure in the Crash Vault before continuing.` : ""}
`;

  await memory.addMessage({
    role: "system",
    content: systemPrompt,
  });

  // Startup Log with Git Status
  let gitCommit = "unknown";
  try {
    const hash = execSync("git rev-parse --short HEAD", { encoding: "utf-8" }).trim();
    const bodyFiles = "src/ package.json tsconfig.json *.sh *.service.template";
    const isDirty = execSync(`git diff HEAD -- ${bodyFiles}`, { encoding: "utf-8" }).trim() !== "";
    gitCommit = isDirty ? `${hash}-dirty` : hash;
  } catch (e) {}

  console.log(`=== Modular Substrate v17 Initialized [${gitCommit}] ===`);

  // Execution Loop
  let running = true;
  while (running) {
    running = await api.step();
  }
}

main().catch((err) => {
  console.error("FATAL CRASH:", err);
  process.exit(1);
});

