          description: {
            type: "string",
            description: "Detailed task description",
          },
          priority: {
            type: "string",
            enum: ["critical", "high", "medium", "low"],
            description: "Task priority. Default: medium",
          },
          estimated_minutes: {
            type: "number",
            description: "Estimated time in minutes",
          },
          goal_id: {
            type: "string",
            description: "Optional goal ID to link this task to",
